# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

-- OpenResty Lua access control script

local auth_token = ngx.req.get_headers()["Authorization"]
if not auth_token then
  -- No authentication token found, deny access
  ngx.exit(403)
end

local user_roles = { "user", "admin" }
local valid_roles = false
for _, role in ipairs(user_roles) do
  if string.find(auth_token, role) then
    valid_roles = true
    break
  end
end

if not valid_roles then
  -- Invalid user roles found, deny access
  ngx.exit(403)
end

-- Check if the URI contains "/admin" or "/api" and skip permission checks for those endpoints
local uri = ngx.var.uri
if string.find(uri, "/admin") or string.find(uri, "/api") then
  return
end

-- Perform permission checks based on user roles
if user_roles[1] == "user" then
  -- User role has limited permissions
  ngx.exit(403)
elseif user_roles[2] == "admin" then
  -- Admin role has full permissions
  return
end